    tr=@("PIR floodlight (mains) | Driveway, back garden | £25 - £55","Solar PIR light | Shed, side gate | £13 - £35","Smart bulb | Internal scheduling | £30 - £35","TV simulator | Lounge deception | £15 - £25");
    fq=@(
